  return {
    total: batchList.value.length,
    running: batchList.value.filter(b => b.status === 'running').length,
    completed: batchList.value.filter(b => b.status === 'completed').length,
    warning: batchList.value.filter(b => b.status === 'error').length
  }
})

// 筛选后的批次列表
const filteredBatchList = computed(() => {
  let result = batchList.value
  if (batchFilter.value !== 'all') {
    result = result.filter(b => b.status === batchFilter.value)
  }
  if (batchSearch.value) {
    result = result.filter(b => b.batchNo.includes(batchSearch.value))
  }
  return result
})

// 筛选后的配方列表
const filteredRecipeList = computed(() => {
  let result = recipeList.value
  if (recipeSearch.value) {
    result = result.filter(r =>
      r.recipeName.includes(recipeSearch.value) ||
      r.recipeCode.includes(recipeSearch.value)
    )
  }
  return result
})

// 启用的配方列表（用于新建批次选择）
const activeRecipes = computed(() => {
  return recipeList.value.filter(r => r.status === 'active')
})

