const copyRecipe = (recipe: Recipe) => {
  ElMessage.success(`已复制配方: ${recipe.recipeName}`)
}

// 删除配方
const deleteRecipe = (recipe: Recipe) => {
  ElMessageBox.confirm(
    `确定要删除配方 "${recipe.recipeName}" 吗？`,
    '确认删除',
    {
      confirmButtonText: '确定',
      cancelButtonText: '取消',
      type: 'warning'
    }
  ).then(() => {
    recipeList.value = recipeList.value.filter(r => r.id !== recipe.id)
    ElMessage.success('删除成功')
  })
}

// 显示新建配方对话框
const showCreateRecipeDialog = () => {
  ElMessage.info('打开新建配方对话框')
}

// 显示新建批次对话框
const showCreateBatchDialog = () => {
  batchForm.value = {
    recipeId: '',
    batchNo: `BT-${new Date().toISOString().slice(0, 10).replace(/-/g, '')}-${String(batchList.value.length + 1).padStart(3, '0')}`,
    productName: '',
    planQty: 100,
    unit: 'kg',
    priority: 'normal',
    remark: ''
  }
  createBatchVisible.value = true
}

// 提交新建批次
const submitCreateBatch = () => {
  batchFormRef.value.validate((valid: boolean) => {
    if (valid) {
      const recipe = recipeList.value.find(r => r.id === batchForm.value.recipeId)
      const newBatch: Batch = {
        id: String(batchList.value.length + 1),
        batchNo: batchForm.value.batchNo,
        recipeId: batchForm.value.recipeId,
        recipeName: recipe?.recipeName || '',
        productName: batchForm.value.productName,
        planQty: batchForm.value.planQty,
        actualQty: null,
        unit: batchForm.value.unit,
        status: 'pending',
        progress: 0,
        startTime: null,
        endTime: null,
        priority: batchForm.value.priority,
        remark: batchForm.value.remark
      }
      batchList.value.unshift(newBatch)
      createBatchVisible.value = false
      ElMessage.success('批次创建成功')
    }
  })
}

// 启动批次
const startBatch = (batch: Batch) => {
  batch.status = 'running'
  batch.startTime = new Date().toLocaleString()
  ElMessage.success(`批次 ${batch.batchNo} 已启动`)
}

// 停止批次
const stopBatch = (batch: Batch) => {
  ElMessageBox.confirm(
    `确定要停止批次 "${batch.batchNo}" 吗？`,
    '确认停止',
    {
      confirmButtonText: '确定',
      cancelButtonText: '取消',
      type: 'warning'
    }
  ).then(() => {
    batch.status = 'error'
    ElMessage.warning(`批次 ${batch.batchNo} 已停止`)
  })
}

// 查看批次详情
const viewBatchDetail = (batch: Batch) => {
  ElMessage.info(`查看批次详情: ${batch.batchNo}`)
}

// 分页处理
const handleBatchSizeChange = (val: number) => {
  batchPage.value.size = val
}

const handleBatchCurrentChange = (val: number) => {
  batchPage.value.current = val
}

const handleRecipeSizeChange = (val: number) => {
  recipePage.value.size = val
}

const handleRecipeCurrentChange = (val: number) => {
  recipePage.value.current = val
}

// ==================== 生命周期 ====================

onMounted(() => {
  // 模拟加载数据
  batchLoading.value = true
  recipeLoading.value = true
  setTimeout(() => {
    batchLoading.value = false
    recipeLoading.value = false
  }, 500)
})
